//	State 0
//		on  "bool", "byte", "int"
//			shift and goto state 1
//		on  "chan"
//			shift and goto state 2
//		on  '['
//			shift and goto state 3
//	State 1
//		Accept
//	State 2
//		on  "bool", "byte", "chan", "int", '['
//			call Type and goto state 1
//	State 3
//		on  ']'
//			shift and goto state 2
//		on  "<-", "false", "true", '(', identifier, int_lit, string_lit
//			call Expression and goto state 4
//	State 4
//		on  ']'
//			shift and goto state 2
//
// Type is used internally from Parse.
func (p *Parser) Type() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(Type), 0)
	// state0:
	accept, errorSet = false, 48
	switch Symbol(p.tok.Ch) {
	case TOK_bool, TOK_byte, TOK_int:
		r = append(r, p.shift())
		goto state1
	case TOK_chan:
		r = append(r, p.shift())
		goto state2
	case TOK_005b:
		r = append(r, p.shift())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 48
	switch Symbol(p.tok.Ch) {
	case TOK_bool, TOK_byte, TOK_chan, TOK_int, TOK_005b:
		r = p.add(r, p.Type())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = false, 14
	switch Symbol(p.tok.Ch) {
	case TOK_005d:
		r = append(r, p.shift())
		goto state2
	case TOK_003c002d, TOK_false, TOK_true, TOK_0028, identifier, int_lit, string_lit:
		r = p.add(r, p.Expression())
		goto state4
	}
	return p.stop(r, accept, errorSet)
state4:
	accept, errorSet = false, 43
	switch Symbol(p.tok.Ch) {
	case TOK_005d:
		r = append(r, p.shift())
		goto state2
	}
	return p.stop(r, accept, errorSet)
}

// VarDecl grammar:
//
//	VarDecl = "var" identifier Type [ "=" Expression ] .
//
//	State 0
//		on  "var"
//			shift and goto state 1
//	State 1
//		on  identifier
//			shift and goto state 2
//	State 2
//		on  "bool", "byte", "chan", "int", '['
//			call Type and goto state 3
//	State 3
//		Accept
//		on  '='
//			shift and goto state 4
//	State 4
//		on  "<-", "false", "true", '(', identifier, int_lit, string_lit
//			call Expression and goto state 5
//	State 5
//		Accept
//
// VarDecl is used internally from Parse.
func (p *Parser) VarDecl() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(VarDecl), 0)
	// state0:
	accept, errorSet = false, 29
	switch Symbol(p.tok.Ch) {
	case TOK_var:
		r = append(r, p.shift())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = false, 45
	switch Symbol(p.tok.Ch) {
	case identifier:
		r = append(r, p.shift())
		goto state2
	}
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 48
	switch Symbol(p.tok.Ch) {
	case TOK_bool, TOK_byte, TOK_chan, TOK_int, TOK_005b:
		r = p.add(r, p.Type())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = true, 41
	switch Symbol(p.tok.Ch) {
	case TOK_003d:
		r = append(r, p.shift())
		goto state4
	}
	return p.stop(r, accept, errorSet)
state4:
	accept, errorSet = false, 17
	switch Symbol(p.tok.Ch) {
	case TOK_003c002d, TOK_false, TOK_true, TOK_0028, identifier, int_lit, string_lit:
		r = p.add(r, p.Expression())
		goto state5
	}
	return p.stop(r, accept, errorSet)
state5:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
}

func (p *Parser) shift() (r int32) {
	r = p.tokIndex
	if !p.eof {
		p.tok = p.Scan()
		p.tokIndex++
		p.eof = p.tok.Ch == rune(TOK_EOF)
	}
	return r
}

func (p *Parser) get() (r []int32) {
	if n := len(p.cache); n != 0 {
		r = p.cache[n-1][:0]
		p.cache = p.cache[:n-1]
	}
	return r
}

func (p *Parser) add(r, s []int32) (t []int32) {
	p.cache = append(p.cache, s)
	return append(r, s...)
}

func (p *Parser) stop(r []int32, accept bool, errorSet int) []int32 {
	r[1] = int32(len(r) - 2)
	if !accept {
		p.err(p.tok.Position(), "%q [%s]: expected %v", p.tok.Src(), Symbol(p.tok.Ch), errorSets[errorSet])
	}
	return r
}

// EOF reports whether the parser lookahead token is EOF.
func (p *Parser) EOF() bool {
	return p.eof
}

// Token returns the n-th token in 'p'. Token panics if 'n' is out of range.
func (p *Parser) Token(n int32) (r scanner.Token) {
	return p.sc.Token(int(n))
}

// Parse parses 'src'. 'src' becomes "owned" by the parser and must not be
// mutated afterwards.
func (p *Parser) Parse(name string, src []byte) (ast []int32, err error) {
	if err = p.init(name, src); err != nil {
		return nil, err
	}

	defer func() {
		switch e := recover(); x := e.(type) {
		case nil:
			// ok
		case scanner.ErrList:
			err = x
		case error:
			err = errors.Join(err, x)
		default:
			err = errors.Join(err, fmt.Errorf("%v", x))
		}
	}()

	p.tok = p.Scan()
	ast = p.SourceFile()
	return ast, p.sc.Err()
}

func (p *Parser) err0(pos token.Position, s string, args ...any) {
	p.sc.AddErr(pos, s, args...)
	if p.errBudget--; p.errBudget == 0 {
		p.sc.AddErr(pos, "too many errors")
	}
}

func (p *Parser) err(pos token.Position, s string, args ...any) {
	p.err0(pos, s, args...)
	p.shift()
	if p.eof {
		panic(p.sc.Err())
	}
}
